const html = $input.first().json.data || '';
const today = new Date().toISOString().split('T')[0];
const articleRegex = /<a href="\/blog\/([^"]+)"[^>]*>.*?<time[^>]*>([^<]+)<\/time>/gs;
const articles = [];
let match;
while ((match = articleRegex.exec(html)) !== null) {
  const slug = match[1];
  const date = match[2].trim();
  if (date === today || slug === 'index') continue;
  articles.push({ article_url: 'https://lysander.bond/blog/' + slug, title: slug });
}
if (articles.length === 0) {
  const latestRegex = /<a href="\/blog\/([^"]+)"[^>]*>.*?<time[^>]*>([^<]+)<\/time>/gs;
  const allArticles = [];
  while ((match = latestRegex.exec(html)) !== null) {
    if (match[1] !== 'index') {
      allArticles.push({ article_url: 'https://lysander.bond/blog/' + match[1], date: match[2].trim() });
    }
  }
  if (allArticles.length > 0) { articles.push(allArticles[0]); }
}
return articles.map(a => ({ json: a }));

const h = $("Fetch Article").first().json.data || "";
const accessToken = $("Get WeChat Access Token").first().json.access_token;
const articleUrl = $("Fetch Article").first().json.article_url || "";
const thumbMediaId = "${WX_THUMB_MEDIA_ID}";
const titleMatch = h.match(/<h1[^>]*>([\\s\\S]*?)<\\/h1>/i);
let title = titleMatch ? titleMatch[1].replace(/<[^>]+>/g, "").trim() : "Untitled";
const proseStart = h.indexOf('class="prose');
const contentStart = h.indexOf(">", proseStart) + 1;
const footerStart = h.indexOf("<footer", proseStart);
let content = h.substring(contentStart, footerStart > 0 ? footerStart : content.length);
let cleanContent = content.replace(/<nav[\\s\\S]*?<\\/nav>/gi, "").replace(/<script[\\s\\S]*?<\\/script>/gi, "").replace(/<style[\\s\\S]*?<\\/style>/gi, "").replace(/<aside[\\s\\S]*?<\\/aside>/gi, "").replace(/\\s*class="[^"]*"/gi, "").replace(/\\s*style="[^"]*"/gi, "");
cleanContent = cleanContent.replace(/<code>/gi, '<code style="background:#f4f4f4;padding:2px 6px;">').replace(/<pre>/gi, '<pre style="background:#f6f8fa;padding:16px;">').replace(/<h2[^>]*>/gi, '<p style="font-size:20px;font-weight:bold;margin:20px 0 10px;">').replace(/<\\/h2>/gi, '</p>').replace(/<h3[^>]*>/gi, '<p style="font-size:17px;font-weight:bold;margin:18px 0 9px;">').replace(/<\\/h3>/gi, '</p>').replace(/<p([^>]*)>/gi, '<p style="margin:12px 0;line-height:1.8;">').replace(/<ul[^>]*>/gi, '<ul style="padding-left:24px;margin:12px 0;">').replace(/<ol[^>]*>/gi, '<ol style="padding-left:24px;margin:12px 0;">').replace(/<li([^>]*)>/gi, '<li style="margin:6px 0;">').replace(/<blockquote[^>]*>/gi, '<blockquote style="border-left:4px solid #4CAF50;margin:16px 0;padding:8px 16px;color:#555;background:#f9f9f9;">').replace(/<img([^>]*)>/gi, '<img$1 style="max-width:100%;border-radius:8px;margin:12px 0;" />').replace(/<div/gi, '<p style="margin:10px 0;"').replace(/<\\/div>/gi, '</p>').replace(/<strong>/gi, '<strong style="font-weight:bold;">').replace(/<em>/gi, '<em style="font-style:italic;">').replace(/<a([^>]*)>/gi, '<a$1 style="color:#1a73e8;text-decoration:underline;">');
const textOnly = cleanContent.replace(/<[^>]+>/g, "").replace(/\\s+/g, " ").trim();
const digest = textOnly.substring(0, 54).replace(/["']/g, "") + "...";
const payload = { articles: [{ title: title, author: "Lysander", digest: digest, content: cleanContent, content_source_url: articleUrl, thumb_media_id: thumbMediaId, need_open_comment: 0, only_fans_can_comment: 0 }] };
return [{ json: { body: JSON.stringify(payload), access_token: accessToken } }];
